for volume in volumes {
                    group.addTask {
                        do {
                            try await ClientVolume.delete(name: volume.id)
                            print(volume.id)
                            return nil
                        } catch {
                            _log.error(
                                "failed to delete volume",
                                metadata: [
                                    "id": "\(volume.id)",
                                    "error": "\(error)",
                                ])
                            return volume
                        }
                    }
                }

                for try await volume in group {
                    guard let volume else {
                        continue
                    }
                    failed.append(volume.id)
                }

